public static long solve(long n, long[][] edges, long k) {
    // Sort edges by time in ascending order
    Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

    // Initialize parent array for Union-Find
    long[] parent = new long[(int) n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }

    // Find function with path compression
    long find(long x, long[] parent) {
        if (parent[x] != x) {
            parent[x] = find(parent[x], parent);
        }
        return parent[x];
    }

    // Union function
    void union(long x, long y, long[] parent) {
        long rootX = find(x, parent);
        long rootY = find(y, parent);
        parent[rootY] = rootX;
    }

    // Count of connected components
    long componentCount = n;

    // Iterate through edges in order of increasing time
    for (long[] edge : edges) {
        long u = edge[0];
        long v = edge[1];
        long time = edge[2];

        // Union the nodes
        union(u, v, parent);

        // Decrease component count if the nodes were in different components
        if (find(u, parent) != find(v, parent)) {
            componentCount--;
        }

        // Check if we have at least k components
        if (componentCount >= k) {
            return time;
        }
    }

    // If we haven't found the answer, return the maximum time (all edges are removed)
    return edges.length > 0 ? edges[edges.length - 1][2] : 0;
}
